var results = $.steps.searchExa.response.results || [];
var best = results[0] || {};
var sources = results.slice(0, 5).map(function(r, i) { return (i + 1) + '. ' + (r.title || 'Untitled') + ' - ' + r.url + '\n   ' + (r.text || '').slice(0, 200); });
return { bestUrl: best.url || '', sources: sources.join('\n\n'), sourceCount: results.length };

var scrapedMd = '';
if ($.steps.scrapeSource.response && $.steps.scrapeSource.response.data) {
  scrapedMd = ($.steps.scrapeSource.response.data.markdown || '').slice(0, 4000);
}
var sources = $.steps.pickBestSource.output.sources;
var prompt = 'You are a knowledgeable research assistant. Answer the following question thoroughly using the provided sources.

QUESTION: ' + $.input.question + '

SEARCH RESULTS SUMMARY:
' + sources + '

DETAILED CONTENT FROM TOP SOURCE:
' + scrapedMd + '

Provide a comprehensive, well-structured answer. Include key facts, cite sources where relevant, and note any caveats. Return ONLY valid JSON:
{
  "answer": "Your detailed answer here",
  "keyPoints": ["point1", "point2"],
  "sources": ["url1", "url2"],
  "confidence": "high|medium|low"
}';
return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':mag: Answer: ' + $.input.question.slice(0, 100), emoji: true } });
var confidenceEmoji = ':large_green_circle:';
if (ai.confidence === 'medium') confidenceEmoji = ':large_yellow_circle:';
if (ai.confidence === 'low') confidenceEmoji = ':red_circle:';
if (ai.answer) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.answer.slice(0, 2900) } });
}
if (ai.keyPoints && ai.keyPoints.length > 0) {
  blocks.push({ type: 'divider' });
  var kpText = '*Key Points*\n';
  ai.keyPoints.forEach(function(p, i) { kpText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText } });
}
if (ai.sources && ai.sources.length > 0) {
  blocks.push({ type: 'divider' });
  var srcText = '*Sources*\n';
  ai.sources.forEach(function(s) { srcText += '- <' + s + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: ' + (ai.confidence || 'unknown') + ' | ' + $.steps.pickBestSource.output.sourceCount + ' sources analyzed' }] });
var fallback = ai.answer ? ai.answer.slice(0, 500) : (ai.text || '').slice(0, 500);
return { blocks, fallback };
